UPDATE public.plataforma_popups SET text = 'O arquivo público do projecto. Arquiva todos os conteúdos (vídeos, textos e verificações) produzidos. Expõe conteúdos do https://www.sns24.gov.pt/pt/info-saude do SNS mas de uma forma mais dinâmica. O que é distribuído pelas redes sociais tem sempre o site como destino e fonte original. O próprio site serve como veículo para chegar a instituições e repositórios na área de ciências da saúde.' WHERE id = 'site';